using System;
using System.Threading;

/// <summary>
/// Migrated from .NET Framework to .NET 8.
/// Thread.Abort throws PlatformNotSupportedException in .NET 6+.
/// Replaced with cooperative cancellation via CancellationToken.
/// </summary>
public class BackgroundProcessor : IDisposable
{
    private Thread? _workerThread;
    private CancellationTokenSource? _cts;

    public void Start()
    {
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _workerThread = new Thread(() => ProcessLoop(token));
        _workerThread.IsBackground = true;
        _workerThread.Start();
    }

    private void ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                var item = GetNextItem(token); // pass token so blocking calls can be interrupted
                ProcessItem(item, token);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Cancellation was requested — clean up partial work
                RollbackCurrentTransaction();
                break; // exit the loop; no need for ResetAbort
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public void Stop()
    {
        if (_cts == null) return;

        _cts.Cancel(); // signal cooperative cancellation

        // Wait up to 2 seconds for the thread to finish gracefully
        if (_workerThread != null && _workerThread.IsAlive)
        {
            _workerThread.Join(TimeSpan.FromSeconds(2));
        }
    }

    public void Dispose()
    {
        Stop();
        _cts?.Dispose();
        _cts = null;
    }
}

